+    #[test]
+    fn error_category_hash_in_set() {
+        use std::collections::HashSet;
+        let mut set = HashSet::new();
+        set.insert(ErrorCategory::Wezterm);
+        set.insert(ErrorCategory::Storage);
+        set.insert(ErrorCategory::Wezterm);
+        assert_eq!(set.len(), 2);
+    }
